diff --git a/src/util/deep-equal.ts b/src/util/deep-equal.ts
+/** Structural equality for primitives, arrays, and plain objects.
+ *  NOTE: does NOT handle Map, Set, or Date — callers must pre-normalize those. */
+export function deepEqual(a: unknown, b: unknown): boolean {
+  if (a === b) return true;
+  if (typeof a !== 'object' || typeof b !== 'object' || a === null || b === null) return false;
+  if (Array.isArray(a) !== Array.isArray(b)) return false;
+  const ka = Object.keys(a as object), kb = Object.keys(b as object);
+  if (ka.length !== kb.length) return false;
+  return ka.every(k => deepEqual((a as Record<string, unknown>)[k], (b as Record<string, unknown>)[k]));
+}
diff --git a/src/util/deep-equal.test.ts b/src/util/deep-equal.test.ts
+test('nested objects equal', () => expect(deepEqual({a:{b:1}}, {a:{b:1}})).toBe(true));
+test('array order matters', () => expect(deepEqual([1,2],[2,1])).toBe(false));
+test('primitive mismatch', () => expect(deepEqual(1,'1')).toBe(false));
